// Validate portfolio rows from Google Sheets

const rows = items.map(item => item.json);

if (!rows || rows.length === 0) {
  throw new Error("Portfolio sheet is empty. Add at least one stock.");
}

const requiredColumns = ["Symbol", "Sector", "Quantity"];

const invalidRows = [];

rows.forEach((row, index) => {
  requiredColumns.forEach(col => {
    if (!row[col]) {
      invalidRows.push(`Row ${index + 2}: Missing ${col}`);
    }
  });

  if (Number(row.Quantity) <= 0) {
    invalidRows.push(`Row ${index + 2}: Quantity must be greater than 0`);
  }
});

if (invalidRows.length > 0) {
  throw new Error(
    "Portfolio validation failed:\n" + invalidRows.join("\n")
  );
}

// Normalize output for downstream nodes
return rows.map(row => ({
  json: {
    symbol: String(row.Symbol).trim().toUpperCase(),
    sector: String(row.Sector).trim(),
    quantity: Number(row.Quantity),
    avg_price: row["Avg Price"] ? Number(row["Avg Price"]) : null
  }
}));

// Basic normalization of Alpha Vantage daily data

const raw = items[0].json;

// Fallback-safe access
const series = raw["Time Series (Daily)"] || {};

// Extract dates (ascending order)
const dates = Object.keys(series).sort();

// Collect closing prices
const prices = dates.map(date => {
  return Number(series[date]["4. close"]);
});

// Current price assumed as last available close
const current_price = prices[prices.length - 1] || 0;

// Compute returns (simple difference-based)
const returns = [];
for (let i = 1; i < prices.length; i++) {
  returns.push(prices[i] - prices[i - 1]);
}

return [
  {
    json: {
      symbol: raw?.["Meta Data"]?.["2. Symbol"] || "UNKNOWN",
      current_price,
      prices,
      returns
    }
  }
];

/**
 * STEP 4 — Portfolio Risk Engine (Defensive Version)
 * Handles invalid / empty symbols safely
 */

// --------------------
// 1. CLEAN INPUT
// --------------------
const rawPortfolio = items.map(i => i.json);

// Remove invalid entries
const portfolio = rawPortfolio.filter(p =>
  p.symbol &&
  p.symbol !== "UNKNOWN" &&
  typeof p.current_price === "number" &&
  p.current_price > 0 &&
  Array.isArray(p.returns) &&
  p.returns.length > 1
);

if (portfolio.length === 0) {
  throw new Error("No valid portfolio items after normalization");
}

// --------------------
// 2. CONFIG
// --------------------
const config = $node["Risk Thresholds and Settings"].json;
const sectorLimitPct = config.sector_concentration_limit;
const corrThreshold = config.correlation_threshold;

// --------------------
// 3. HELPERS
// --------------------
const mean = arr =>
  arr.reduce((a, b) => a + b, 0) / arr.length;

const stdDev = arr => {
  if (arr.length < 2) return 0;
  const m = mean(arr);
  return Math.sqrt(
    mean(arr.map(x => Math.pow(x - m, 2)))
  );
};

const correlation = (a, b) => {
  const len = Math.min(a.length, b.length);
  if (len < 2) return 0;

  const aSlice = a.slice(0, len);
  const bSlice = b.slice(0, len);

  const meanA = mean(aSlice);
  const meanB = mean(bSlice);

  let num = 0, denA = 0, denB = 0;

  for (let i = 0; i < len; i++) {
    num += (aSlice[i] - meanA) * (bSlice[i] - meanB);
    denA += Math.pow(aSlice[i] - meanA, 2);
    denB += Math.pow(bSlice[i] - meanB, 2);
  }

  return num / Math.sqrt(denA * denB || 1);
};

// --------------------
// 4. PORTFOLIO VALUE
// --------------------
portfolio.forEach(p => {
  p.market_value = p.current_price * (p.quantity || 1);
});

const totalValue = portfolio.reduce(
  (sum, p) => sum + p.market_value,
  0
);

// --------------------
// 5. SECTOR CONCENTRATION
// --------------------
const sectorMap = {};
portfolio.forEach(p => {
  const sector = p.sector || "Unknown";
  sectorMap[sector] =
    (sectorMap[sector] || 0) + p.market_value;
});

const sector_concentration = Object.entries(sectorMap).map(
  ([sector, value]) => {
    const weight = (value / totalValue) * 100;
    return {
      sector,
      weight_pct: +weight.toFixed(2),
      risk: weight > sectorLimitPct
    };
  }
);

// --------------------
// 6. VOLATILITY
// --------------------
portfolio.forEach(p => {
  p.volatility = stdDev(p.returns);
});

const portfolio_volatility = mean(
  portfolio.map(p => p.volatility)
);

// --------------------
// 7. CORRELATION
// --------------------
const correlation_flags = [];

for (let i = 0; i < portfolio.length; i++) {
  for (let j = i + 1; j < portfolio.length; j++) {
    const corr = correlation(
      portfolio[i].returns,
      portfolio[j].returns
    );

    if (Math.abs(corr) >= corrThreshold) {
      correlation_flags.push({
        pair: `${portfolio[i].symbol} – ${portfolio[j].symbol}`,
        correlation: +corr.toFixed(2)
      });
    }
  }
}

// --------------------
// 8. RISK FLAGS + SCORE
// --------------------
const sectorRisk = sector_concentration.some(s => s.risk);
const correlationRisk = correlation_flags.length > 0;
const volatilityRisk = portfolio_volatility > 0;

let risk_score = 0;
if (sectorRisk) risk_score += 35;
if (correlationRisk) risk_score += 35;
if (volatilityRisk) risk_score += 30;

// --------------------
// 9. FINAL OUTPUT
// --------------------
return [
  {
    json: {
      portfolio_size: portfolio.length,
      portfolio_value: +totalValue.toFixed(2),

      sector_concentration,
      stock_volatility: portfolio.map(p => ({
        symbol: p.symbol,
        volatility: +p.volatility.toFixed(4)
      })),

      portfolio_volatility: +portfolio_volatility.toFixed(4),
      correlation_flags,

      risk_detected:
        sectorRisk || correlationRisk || volatilityRisk,

      risk_score
    }
  }
];

